css:
@page {
  size: A4; margin: 18mm 18mm 22mm 18mm;
  @bottom-left { content: "Beispiel Cloud GmbH · Marktplatz 1 · 10115 Berlin \A Amtsgericht Charlottenburg · HRB 123456 \A Geschäftsführer: Max Beispiel"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; vertical-align: top; padding-top: 4mm; }
  @bottom-center { content: "Seite " counter(page) " von " counter(pages); font-size: 6.5pt; color: #8a8a8a; white-space: nowrap; vertical-align: top; padding-top: 4mm; }
  @bottom-right { content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A IBAN DE89 3704 0044 0532 0130 00 · BIC COBADEFFXXX"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm; }
}

body { color: #0a0a0a; font-family: 'Helvetica', 'Arial', sans-serif; }
.mono { font-family: 'SFMono-Regular', 'Courier New', monospace; letter-spacing: -0.02em; }
.doc-header { display: block; margin: 0; }

.sa-top { display: flex; align-items: center; justify-content: space-between; }
.sa-brand { display: flex; align-items: center; gap: 3mm; }
.sa-mark { height: 9mm; width: 9mm; display: block; }
.sa-brandname { font-size: 12pt; font-weight: 700; }
.sa-doc { text-align: right; }
.sa-eyebrow { display: block; font-size: 8pt; letter-spacing: 0.2em; color: #9ca3af; font-weight: 700; }
.sa-docno { display: block; font-size: 12pt; font-weight: 700; margin-top: 1mm; }

/* Headline amount */
.sa-headline { margin: 10mm 0 8mm; }
.sa-headline h1 { font-size: 34pt; font-weight: 800; letter-spacing: -0.03em; margin: 0; font-variant-numeric: tabular-nums; }
.sa-headline p { color: #6b7280; font-size: 10pt; margin-top: 2mm; }

/* KPI tiles */
.sa-kpis { display: flex; gap: 3mm; margin-bottom: 9mm; }
.sa-kpi { flex: 1 1 0; border: 1px solid #ececec; border-radius: 2.5mm; padding: 4mm; }
.sa-kpi__v { font-size: 15pt; font-weight: 800; letter-spacing: -0.02em; font-variant-numeric: tabular-nums; }
.sa-kpi__k { font-size: 7.5pt; letter-spacing: 0.08em; text-transform: uppercase; color: #9ca3af; font-weight: 600; margin-top: 1.5mm; }

/* Items */
.sa-items { width: 100%; border-collapse: collapse; margin-bottom: 9mm; }
.sa-items thead th { font-size: 7pt; letter-spacing: 0.14em; text-transform: uppercase; color: #9ca3af; font-weight: 700; text-align: left; padding: 0 0 3mm; border-bottom: 1px solid #0a0a0a; }
.sa-items tbody td { padding: 3.4mm 0; border-bottom: 1px solid #f0f0f0; vertical-align: top; }
.sa-c-desc { width: 52mm; }
.sa-c-desc strong { font-weight: 700; }
.sa-c-meta { color: #6b7280; font-size: 9pt; padding-right: 6mm; }
.sa-c-qty { width: 26mm; text-align: right; color: #6b7280; }
.sa-c-total { width: 30mm; text-align: right; font-weight: 700; }
thead th.sa-c-qty, thead th.sa-c-total { text-align: right; }

/* Footer */
.sa-foot { display: flex; gap: 10mm; align-items: flex-start; }
.sa-pay { flex: 1 1 0; }
.sa-card { border: 1px solid #ececec; border-radius: 2.5mm; padding: 5mm; }
.sa-k { font-size: 7pt; letter-spacing: 0.12em; text-transform: uppercase; color: #9ca3af; font-weight: 700; }
.sa-pay__method { font-size: 12pt; font-weight: 700; margin-top: 1.5mm; }
.sa-pay__note { font-size: 8.5pt; color: #6b7280; line-height: 1.5; margin-top: 2.5mm; }
.sa-totals { flex: 0 0 70mm; }
.sa-trow { display: flex; justify-content: space-between; padding: 2mm 0; font-size: 10pt; }
.sa-trow span:first-child { color: #6b7280; }
.sa-trow--grand { margin-top: 1.5mm; padding-top: 3mm; border-top: 1px solid #0a0a0a; font-size: 14pt; font-weight: 800; }
.sa-trow--grand span:first-child { color: #0a0a0a; }
.sa-gradient { height: 1.4mm; border-radius: 1mm; margin-top: 3mm; background: linear-gradient(90deg, #7c3aed 0%, #2563eb 100%); }
